import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read the entire input

        char[] buffer = new char[10];

        // Ensure that only up to 10 characters are copied into the buffer
        for (int i = 0; i < Math.min(name.length(), 10); i++) {
            buffer[i] = name.charAt(i);
        }

        // Print out the sanitized buffer content
        System.out.print("Sanitized Buffer Content: ");
        for (char c : buffer) {
            System.out.print(c);
        }
    }
}

